// Full Video Generation — capability guard
//
// MEDIA_MODE=full_video requires a provider with native video generation
// capability (fullVideoGeneration: true in MEDIA_PROVIDER_CAPABILITIES).
//
// No v1 provider (openai, google) supports this capability.
// The orchestrator's Check Media Mode node blocks this path at startup,
// so this node will only execute in a future release when a compatible
// provider is available.
//
// This node performs a final safety check and produces a structured
// full_video_generation_asset with status='failed' and a clear warning
// so the pipeline can degrade gracefully rather than silently corrupt
// the daily output.

const ctx = $input.first().json;
const topic_slug = ctx.topic_slug;
const date_key   = ctx.date_key;
const now        = new Date().toISOString();

// Provider capability check (mirrors MEDIA_PROVIDER_CAPABILITIES in mediaMode.js)
const FULL_VIDEO_CAPABLE_PROVIDERS = [];
// No providers support fullVideoGeneration in v1.
// Add provider slugs here when a capable provider becomes available.

const provider = (ctx.ai_provider || $vars.AI_PROVIDER || 'openai').trim();

if (!FULL_VIDEO_CAPABLE_PROVIDERS.includes(provider)) {
  // Produce a graceful failed asset rather than crashing the pipeline.
  // Captions are still generated from the video script so they are
  // available for YouTube upload even when video generation fails.
  const video_script = ctx.video_script || {};
  const captions_srt = buildCaptionsFromScript(video_script);

  return [{
    json: {
      ...ctx,
      full_video_generation_asset: {
        topic_slug,
        date_key,
        status:            'failed',
        provider:          'none',
        model:             null,
        generation_job_id: null,
        video_url:         null,
        duration_seconds:  null,
        resolution:        null,
        captions_srt,
        captions_format:   captions_srt ? 'srt' : 'none',
        scene_count:       null,
        prompt_tokens:     null,
        generated_at:      now,
        warning:
          `MEDIA_MODE_CONFIG_ERROR: full_video mode requires a provider with ` +
          `fullVideoGeneration capability. Provider "${provider}" does not support ` +
          `this in v1. Set MEDIA_MODE=image_video to use the default pipeline, ` +
          `or configure a capable provider when one becomes available.`,
      },
    },
  }];
}

// ---------------------------------------------------------------------------
// Future implementation entry point
// ---------------------------------------------------------------------------
// When a capable provider is added to FULL_VIDEO_CAPABLE_PROVIDERS above,
// implement the generation call here. Expected output must conform to
// schemas/ai/full_video_generation_asset.json.
//
// Minimum steps:
//   1. Build scene prompts from ctx.video_script.segments
//   2. Submit to provider API (may be async — store generation_job_id)
//   3. Poll or await callback for completed video_url
//   4. Generate SRT captions from video_script (always, regardless of provider status)
//   5. Return accumulated context extended with full_video_generation_asset
//
// See docs/architecture/full-video-mode.md for the full design and provider
// integration requirements.
throw new Error(
  `full_video mode reached generation step with provider "${provider}" ` +
  `but FULL_VIDEO_CAPABLE_PROVIDERS is empty. ` +
  `Update this list when a capable provider is configured.`
);

// ---------------------------------------------------------------------------
// Caption generation helper (identical algorithm to 06d_render_video.json)
// ---------------------------------------------------------------------------
function buildCaptionsFromScript(script) {
  if (!script || !Array.isArray(script.segments)) return null;
  const WORDS_PER_SECOND = 2.5;
  const lines = [];
  let sequenceNumber = 1;
  let offsetSeconds  = 0;

  function formatSrtTime(seconds) {
    const h  = Math.floor(seconds / 3600);
    const m  = Math.floor((seconds % 3600) / 60);
    const s  = Math.floor(seconds % 60);
    const ms = Math.round((seconds % 1) * 1000);
    return [
      String(h).padStart(2, '0'),
      String(m).padStart(2, '0'),
      String(s).padStart(2, '0'),
    ].join(':') + ',' + String(ms).padStart(3, '0');
  }

  function appendText(text, durationSeconds) {
    const words    = text.trim().split(/\s+/);
    const chunkSz  = 8;
    const total    = words.length;
    const duration = durationSeconds || Math.max(2, total / WORDS_PER_SECOND);
    const timePerWord = duration / Math.max(total, 1);
    for (let i = 0; i < total; i += chunkSz) {
      const chunk     = words.slice(i, i + chunkSz).join(' ');
      const startSec  = offsetSeconds + i * timePerWord;
      const endSec    = Math.min(offsetSeconds + duration, startSec + chunkSz * timePerWord);
      lines.push(
        `${sequenceNumber}`,
        `${formatSrtTime(startSec)} --> ${formatSrtTime(endSec)}`,
        chunk,
        ''
      );
      sequenceNumber++;
    }
    offsetSeconds += duration;
  }

  if (script.intro) appendText(script.intro, null);
  for (const seg of script.segments) {
    appendText(seg.script || '', seg.duration_seconds || null);
  }
  if (script.outro) appendText(script.outro, null);
  return lines.join('\n');
}
